// --- CONFIGURAZIONE UI ---
// Usiamo u da -1 a 1 per rappresentare le due metà (Sotto -> Sopra)
u_min := -1.0; 
u_max := 1.0; 
v_min := -3.14159;
v_max := 3.14159;
steps := 300;  // Alta qualità per la giunzione
A := 10.0;     // k
B := 0.1;     // SCALA
C := 0.0;     

// --- INIZIO GLSL ---

float k = u_mathParams.x;    // 10
float scale = u_mathParams.y;// 0.04

// 1. MAPPING INTELLIGENTE DEL RAGGIO
// Invece di disegnare da 0 a 1, mappiamo l'input [-1...1] 
// nel range reale della figura [0.28...1.1].
// Questo salta la parte centrale "brutta" e unisce i bordi interni.
float u_input = u;
float u_real = 0.28 + abs(u_input) * (1.09 - 0.28);

// 2. Calcolo Geometria Base (Usando il raggio mappato positivo)
float v_val = v; // Usiamo v normale (giro completo)

float pow_u_2k_1 = pow(u_real, 2.0 * k - 1.0);
float pow_u_k    = pow(u_real, k);

float x = k * u_real * cos(v_val) - (pow_u_2k_1 / 6.0) * cos((2.0 * k - 1.0) * v_val);
float y = -k * u_real * sin(v_val) - (pow_u_2k_1 / 6.0) * sin((2.0 * k - 1.0) * v_val);
float z_base = -(pow_u_k * cos(k * v_val));

// 3. SELEZIONE FACCIA (Sopra o Sotto)
// Se u è negativo, facciamo la faccia 1. Se positivo, la faccia 2.
// Il punto u=0 diventa la cucitura perfetta al centro del buco.

float shift = 2.0 * exp(2.0 * cos(4.0 * u_real));
float constant = 24.0 / 5.0; // 4.8
float finalZ;

if (u_input < 0.0) {
    // Componente 1 (Sotto)
    finalZ = z_base - shift + constant;
} else {
    // Componente 2 (Sopra)
    finalZ = -z_base + shift - constant;
}

// 4. Output
return vec4(x * scale, y * scale, finalZ * scale, 0.0);
